import React from 'react';
import { Card, CardMedia, CardContent, Typography, Button, Box, LinearProgress, Chip, useTheme } from '@mui/material';
import { styled } from '@mui/material/styles';
import { CalendarMonth, Person, Speed } from '@mui/icons-material';
import { motion } from 'framer-motion';
import { Link } from 'react-router-dom';

const MotionCard = styled(motion.div)(({ theme }) => ({
  borderRadius: 16,
  overflow: 'hidden',
  width: '100%',
  marginBottom: 20,
  boxShadow: theme.palette.mode === 'light' 
    ? '0 8px 24px rgba(0,0,0,0.12)'
    : '0 8px 24px rgba(0,0,0,0.3)',
  transition: 'transform 0.3s ease-in-out, box-shadow 0.3s ease-in-out',
  background: theme.palette.mode === 'light'
    ? 'linear-gradient(135deg, #ffffff 0%, #f7f9fc 100%)'
    : 'linear-gradient(135deg, #1e1e1e 0%, #2d2d2d 100%)',
}));

const CardDetailsContainer = styled(CardContent)(({ theme }) => ({
  padding: theme.spacing(2, 3, 3),
}));

const InfoRow = styled(Box)(({ theme }) => ({
  display: 'flex',
  alignItems: 'center',
  marginBottom: theme.spacing(1),
  '& svg': {
    marginRight: theme.spacing(1),
    fontSize: 20,
    color: theme.palette.text.secondary,
  }
}));

const BuyButton = styled(Button)(({ theme }) => ({
  borderRadius: 12,
  padding: theme.spacing(1, 3),
  fontWeight: 600,
  textTransform: 'none',
  boxShadow: '0 4px 12px rgba(33, 150, 243, 0.3)',
  transition: 'all 0.2s ease-in-out',
  background: 'linear-gradient(90deg, #2196F3 0%, #1976D2 100%)',
  '&:hover': {
    boxShadow: '0 6px 16px rgba(33, 150, 243, 0.5)',
    transform: 'translateY(-2px)',
  }
}));

const ProgressLabel = styled(Box)(({ theme }) => ({
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
  width: '100%',
  marginTop: theme.spacing(0.5),
  marginBottom: theme.spacing(2),
}));

interface CarCardProps {
  id: string;
  title: string;
  image: string;
  description: string;
  ticketsSold: number;
  totalTickets: number;
  price: number;
  year: number;
  participants: number;
  endDate: string;
}

const CarCard: React.FC<CarCardProps> = ({
  id,
  title,
  image,
  description,
  ticketsSold,
  totalTickets,
  price,
  year,
  participants,
  endDate
}) => {
  const progress = (ticketsSold / totalTickets) * 100;
  const formattedPrice = new Intl.NumberFormat('ru-RU').format(price);
  const theme = useTheme();
  
  return (
    <Link to={`/raffles/${id}`} style={{ textDecoration: 'none' }}>
      <MotionCard
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.4 }}
        whileHover={{ scale: 1.02 }}
      >
        <Card elevation={0} sx={{ backgroundColor: 'transparent' }}>
          <CardMedia
            component="img"
            height="200"
            image={image}
            alt={title}
            sx={{ objectFit: 'cover' }}
          />
          
          <CardDetailsContainer>
            <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', mb: 1 }}>
              <Typography gutterBottom variant="h5" component="div" sx={{ fontWeight: 700, mb: 0 }}>
                {title}
              </Typography>
              <Chip 
                label={`${formattedPrice} ₽`} 
                color="primary"
                sx={{ 
                  fontWeight: 700,
                  background: 'linear-gradient(90deg, #2196F3 0%, #1976D2 100%)',
                  color: 'white',
                }}
              />
            </Box>
            
            <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
              {description}
            </Typography>
            
            <Box sx={{ mb: 2 }}>
              <Box sx={{ display: 'flex', gap: 1, mb: 2 }}>
                <InfoRow>
                  <CalendarMonth fontSize="small" />
                  <Typography variant="body2" color="text.secondary">
                    {year} год
                  </Typography>
                </InfoRow>
                
                <InfoRow>
                  <Person fontSize="small" />
                  <Typography variant="body2" color="text.secondary">
                    {participants} участников
                  </Typography>
                </InfoRow>
              </Box>
              
              <Box>
                <LinearProgress 
                  variant="determinate" 
                  value={progress} 
                  sx={{ 
                    height: 8, 
                    borderRadius: 4, 
                    backgroundColor: 'rgba(33, 150, 243, 0.2)',
                    '& .MuiLinearProgress-bar': {
                      borderRadius: 4,
                      background: 'linear-gradient(90deg, #2196F3 0%, #1976D2 100%)',
                    }
                  }} 
                />
                <ProgressLabel>
                  <Typography variant="caption" color="text.secondary">
                    Продано {ticketsSold} из {totalTickets}
                  </Typography>
                  <Typography variant="caption" color="text.secondary">
                    {progress.toFixed(0)}%
                  </Typography>
                </ProgressLabel>
              </Box>
              
              <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <Typography variant="body2" color="text.secondary">
                  До {endDate}
                </Typography>
                <motion.div whileTap={{ scale: 0.95 }}>
                  <BuyButton 
                    variant="contained" 
                    size="medium" 
                    color="primary"
                  >
                    Купить билет
                  </BuyButton>
                </motion.div>
              </Box>
            </Box>
          </CardDetailsContainer>
        </Card>
      </MotionCard>
    </Link>
  );
};

export default CarCard;
